// File: gameApi.js
/* Facade over Grepolis internals. Single source of truth for game access.
   Every accessor is defensive: on failure it logs once and returns a safe default,
   so a game update can never throw an uncaught error inside the bot loop. */
class GameApi {
    static _warned = new Set();

    static _safe(label, fn, fallback) {
        try {
            return fn();
        } catch (e) {
            if (!GameApi._warned.has(label)) {
                GameApi._warned.add(label);
                console.warn(`[ModernBot][GameApi] "${label}" failed — game internals may have changed:`, e);
            }
            return fallback;
        }
    }

    /* --- Identity / world --- */
    static worldId() {
        return GameApi._safe('worldId', () => uw.Game.world_id, 'unknown');
    }

    /* --- Towns --- */
    static getTowns() {
        return GameApi._safe('getTowns',
            () => uw.MM.getOnlyCollectionByName('Town').models, []);
    }
    static getCurrentTown() {
        return GameApi._safe('getCurrentTown', () => uw.ITowns.getCurrentTown(), null);
    }
    static getTown(townId) {
        return GameApi._safe('getTown',
            () => uw.ITowns.getTown(townId) || uw.ITowns.towns[townId], null);
    }
    static getResources(townId) {
        return GameApi._safe('getResources', () => {
            const t = GameApi.getTown(townId);
            return t ? t.resources() : null;
        }, null);
    }

    /* --- Game data --- */
    static getUnitData(unit) {
        return GameApi._safe('getUnitData', () => uw.GameData?.units?.[unit] || null, null);
    }
    static isAdvisorActive(name) {
        return GameApi._safe('isAdvisorActive',
            () => uw.GameDataPremium.isAdvisorActivated(name), false);
    }

    /* --- Networking --- */
    static ajaxPost(controller, action, data, onSuccess) {
        return GameApi._safe('ajaxPost',
            () => uw.gpAjax.ajaxPost(controller, action, data, false, onSuccess), null);
    }
    static ajaxGet(controller, action, data, onSuccess) {
        return GameApi._safe('ajaxGet',
            () => uw.gpAjax.ajaxGet(controller, action, data, false, onSuccess), null);
    }

    /* --- UI feedback --- */
    static notifySuccess(msg) {
        GameApi._safe('notifySuccess', () => uw.HumanMessage?.success?.(msg));
    }
    static notifyError(msg) {
        GameApi._safe('notifyError', () => uw.HumanMessage?.error?.(msg));
    }

    /* --- Buildings / Trade capacity --- */
    static getBuildings(townId) {
        return GameApi._safe('getBuildings', () => {
            const t = GameApi.getTown(townId);
            return t ? t.buildings().attributes : {};
        }, {});
    }
    static availableTradeCapacity(townId) {
        return GameApi._safe('tradeCapacity', () => {
            const t = GameApi.getTown(townId);
            return t ? t.getAvailableTradeCapacity() : 0;
        }, 0);
    }

    /* --- Farm towns --- */
    static getFarmTowns() {
        return GameApi._safe('getFarmTowns',
            () => uw.MM.getOnlyCollectionByName('FarmTown')?.models || [], []);
    }
    static getFarmPlayerRelations() {
        return GameApi._safe('getFarmRelations',
            () => uw.MM.getOnlyCollectionByName('FarmTownPlayerRelation')?.models || [], []);
    }

    /* --- Trade overview --- */
    static getAllTrades() {
        return new Promise(resolve => {
            GameApi.ajaxGet('town_overviews', 'trade_overview', {}, data => {
                resolve(GameApi._safe('parseTrades', () => data?.movements || [], []));
            });
            setTimeout(() => resolve([]), 5000);
        });
    }

    /* --- Units / mods --- */
    static getUnitBuildMod(townId, unitData) {
        return GameApi._safe('unitBuildMod',
            () => uw.GeneralModifications?.getUnitBuildResourcesModification?.(townId, unitData) || 1, 1);
    }
    static getAvailablePop(townId) {
        return GameApi._safe('availablePop', () => {
            const t = GameApi.getTown(townId);
            return t ? t.getAvailablePopulation() : 0;
        }, 0);
    }

    /* --- Observables --- */
    static onWindowOpen(cb) {
        try { uw.$.Observer(uw.GameEvents.window.open).subscribe(cb); } catch(e) {}
    }
    static onTownSwitch(cb) {
        try { uw.$.Observer(uw.GameEvents.town.town_switch).subscribe('modernBotTown', cb); } catch(e) {}
    }

    /* --- Player / Models --- */
    static playerId() {
        return GameApi._safe('playerId', () => uw.Game.player_id, null);
    }
    static getModels() {
        return GameApi._safe('getModels', () => uw.MM.getModels(), {});
    }
    static getModelByNameAndPlayerId(name) {
        return GameApi._safe('model_' + name,
            () => uw.MM.getModelByNameAndPlayerId(name), null);
    }

    /* --- Buildings data --- */
    static getBuildingData(name) {
        return GameApi._safe('getBuildingData', () => uw.GameData?.buildings?.[name], null);
    }
    static getBuildingBuildData(townId) {
        return GameApi._safe('getBuildingBuildData',
            () => uw.MM?.getModels?.()?.BuildingBuildData?.[townId]?.attributes?.building_data, null);
    }
    static getCastedPowers() {
        return GameApi._safe('getCastedPowers',
            () => uw.MM?.getFirstTownAgnosticCollectionByName?.('CastedPowers')?.fragments, {});
    }
    static unitDiscount(townId, unitData) {
        return GameApi._safe('unitDiscount',
            () => uw.GeneralModifications?.getUnitBuildResourcesModification?.(townId, unitData) || 1, 1);
    }

    /* --- Ajax with error handler --- */
    static ajaxPostWithHandlers(controller, action, data, onSuccess, onError) {
        return GameApi._safe('ajaxPostHandlers',
            () => uw.gpAjax.ajaxPost(controller, action, data, false, onSuccess, onError), null);
    }
    /* --- Monkey-patch for attack command ID --- */
    static hookWindowCreateForCommandId(setId) {
        const mgr = uw.GPWindowMgr;
        if (mgr._modernOrigCreate) return;
        mgr._modernOrigCreate = mgr.Create;
        mgr.Create = function (type, title, params, id) {
            if (type === mgr.TYPE_ATK_COMMAND && id) setId(id);
            return mgr._modernOrigCreate.apply(this, arguments);
        };
    }

    /* --- Collections --- */
    static getCollection(name) {
        return GameApi._safe('collection_' + name,
            () => uw.MM.getOnlyCollectionByName(name)?.models || [], []);
    }

    /* --- Town coordinates --- */
    static getIslandX(townId) {
        return GameApi._safe('islandX', () => {
            const t = GameApi.getTown(townId);
            return t ? t.getIslandCoordinateX() : 0;
        }, 0);
    }
    static getIslandY(townId) {
        return GameApi._safe('islandY', () => {
            const t = GameApi.getTown(townId);
            return t ? t.getIslandCoordinateY() : 0;
        }, 0);
    }

    /* --- Bot-blocking detection --- */
    static isCaptchaActive() {
        // Any of these selectors present => a human check is on screen.
        return $('.botcheck').length > 0
            || $('#recaptcha_window').length > 0
            || $('.g-recaptcha').length > 0
            || $('#captcha_curtain').length > 0;
    }
}


// File: utils.js
class ModernUtils {

    saveSettings(id, settings) {
        localStorage.setItem(`modern_settings_${id}`, JSON.stringify(settings));
    }

    loadSettings(id, defaultSettings) {
        const settings = localStorage.getItem(`modern_settings_${id}`);
        if (!settings) return defaultSettings;
        return JSON.parse(settings);
    }

    sleep(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    getTitleElement(text, desc = '(click to toggle)') {
        const $container = $('<div>').addClass('game_border').css({ cursor: 'pointer' })

        // Append each border element
        $container.append($('<div>').addClass('game_border_top'));
        $container.append($('<div>').addClass('game_border_bottom'));
        $container.append($('<div>').addClass('game_border_left'));
        $container.append($('<div>').addClass('game_border_right'));
        $container.append($('<div>').addClass('game_border_corner corner1'));
        $container.append($('<div>').addClass('game_border_corner corner2'));
        $container.append($('<div>').addClass('game_border_corner corner3'));
        $container.append($('<div>').addClass('game_border_corner corner4'));

        const $text = $('<div>').addClass('game_header bold').text(text);
        $container.append($text);

        const $desc = $('<div>').addClass("modern_title_description").text(desc);
        $text.append($desc);

        // Return the container jQuery element
        return { $container: $container, $title: $text };
    }

    getButtonElement(text) {
        const $button = $('<div>', {
            'class': 'button_new',
        });

        // Add the left and right divs to the button
        $button.append($('<div>', { 'class': 'left' }));
        $button.append($('<div>', { 'class': 'right' }));
        $button.append($('<div>', {
            'class': 'caption js-caption',
            'html': `${text} <div class="effect js-effect"></div>`
        }));

        return $button;
    }

    jitter(base) {
        return base + Math.floor(Math.random() * base * 0.5);
    }

    shouldSkip() {
        // Randomly skip ~10% of cycles for anti-pattern disguise
        return Math.random() < 0.1;
    }

}



// File: window.js
class createGrepoWindow {
    constructor({ id, title, size, tabs, start_tab, minimizable = true }) {
        this.minimizable = minimizable;
        this.width = size[0];
        this.height = size[1];
        this.title = title;
        this.id = id;
        this.tabs = tabs;
        this.start_tab = start_tab;

        /* Private methods */
        const createWindowType = (name, title, width, height, minimizable) => {
            function WndHandler(wndhandle) {
                this.wnd = wndhandle;
            }
            Function.prototype.inherits.call(WndHandler, uw.WndHandlerDefault);
            WndHandler.prototype.getDefaultWindowOptions = function () {
                return {
                    position: ['center', 'center', 100, 100],
                    width: width,
                    height: height,
                    minimizable: minimizable,
                    title: title,
                };
            };
            uw.GPWindowMgr.addWndType(name, `${name}_75624`, WndHandler, 1);
        };

        const getTabById = (id) => {
            return this.tabs.filter((tab) => tab.id === id)[0];
        };

        this.activate = function () {
            createWindowType(this.id, this.title, this.width, this.height, this.minimizable); //
            uw.$(
                `<style id="${this.id}_custom_window_style">
                 #${this.id} .tab_icon { left: 23px;}
                 #${this.id} {top: -36px; right: 95px;}
                 #${this.id} .submenu_link:hover {text-decoration: none;}
                 #${this.id} { display: flex; flex-wrap: wrap; }
                 #${this.id} li { float: none; min-width: 56px; }
                 #${this.id}_content { clear: both; padding-top: 8px; margin-top: 8px; }
                 </style>
                `,
            ).appendTo('head');
        };

        this.deactivate = function () {
            if (uw.Layout.wnd.getOpenFirst(uw.GPWindowMgr[`TYPE_${this.id}`])) {
                uw.Layout.wnd.getOpenFirst(uw.GPWindowMgr[`TYPE_${this.id}`]).close();
            }
            uw.$(`#${this.id}_custom_window_style`).remove();
        };

        /* open the window */
        this.openWindow = function () {
            let wn = uw.Layout.wnd.getOpenFirst(uw.GPWindowMgr[`TYPE_${this.id}`]);

            /* if open is called but window it's alreay open minimized, maximize that */
            if (wn) {
                if (wn.isMinimized()) {
                    wn.maximizeWindow();
                }
                return;
            }

            let content = `<ul id="${this.id}" class="menu_inner"></ul><div id="${this.id}_content"> </div>`;
            uw.Layout.wnd.Create(uw.GPWindowMgr[`TYPE_${this.id}`]).setContent(content);
            // Force high-contrast styling
            uw.$(`#${this.id}_content`).css({
                'font-size': '13px',
                'background': '#0d0d0d',
                'color': '#f0e6d2',
            });
            /* Add and reder tabs */
            console.log(this.tabs);
            this.tabs.forEach((e) => {
                let html = `
                    <li><a id="${e.id}" class="submenu_link" href="#"><span class="left"><span class="right"><span class="middle">
                    <span class="tab_label"> ${e.title} </span>
                    </span></span></span></a></li>
                `;
                uw.$(html).appendTo(`#${this.id}`);
            });

            /* Add events to tabs */
            let tabs = '';
            this.tabs.forEach((e) => {
                tabs += `#${this.id} #${e.id}, `;
            });
            tabs = tabs.slice(0, -2);
            let self = this;
            uw.$(tabs).click(function () {
                self.renderTab(this.id);
            });
            /* render default tab*/
            this.renderTab(this.tabs[this.start_tab].id);
        };

        this.closeWindow = function () {
            uw.Layout.wnd.getOpenFirst(uw.GPWindowMgr[`TYPE_${this.id}`]).close();
        };

        /* Handle active tab */
        this.renderTab = function (id) {
            let tab = getTabById(id);
            uw.$(`#${this.id}_content`)
                .html(getTabById(id).render())
                .css({ 'font-size': '13px', 'background': '#0d0d0d', 'color': '#f0e6d2' });
            uw.$(`#${this.id} .active`).removeClass('active');
            uw.$(`#${id}`).addClass('active');
            getTabById(id).afterRender ? getTabById(id).afterRender() : '';
        };
    }
}


// Module: antiRage.js
class AntiRage extends ModernUtils {
    GOODS_ICONS = {
        athena: 'js-power-icon.animated_power_icon.animated_power_icon_45x45.power_icon45x45.power.strength_of_heroes',
        zeus: 'js-power-icon.animated_power_icon.animated_power_icon_45x45.power_icon45x45.power.fair_wind',
        artemis: 'js-power-icon.animated_power_icon.animated_power_icon_45x45.power_icon45x45.power.effort_of_the_huntress',
    };

    constructor() {
        super();
        this.loopFunct = null;
        this.activeGodEl = null;
        this.commandId = null;

        GameApi.hookWindowCreateForCommandId(id => { this.commandId = id; });

        GameApi.onWindowOpen((e, data) => {
            if (data.context !== 'atk_command') return;
            let max = 10;
            const addSpell = () => {
                const spellMenu = $('#command_info-god')[0];
                if (!spellMenu) { if (max > 0) { max--; setTimeout(addSpell, 50); } return; }
                $(spellMenu).on('click', () => this.trigger());
                this.commandId = this.commandId;
            };
            setTimeout(addSpell, 50);
        });
    }

    render() {
        const title = this.getTitleElement('Anti Rage');
        const $body = $('<div>').css({ padding: '8px' });
        $body.html('<p>Detects attack command window, highlights gods, auto-casts anti-rage spells.</p>'
            + '<p>Select a god in the attack window to activate auto-casting.</p>');
        title.$container.append($body);
        return title.$container;
    }

    trigger() {
        setTimeout(() => {
            this.handleGod('athena');
            this.handleGod('zeus');
            this.handleGod('artemis');
        }, 100);
    }

    handleGod(god) {
        const godEl = $(`.god_mini.${god}.${god}`).eq(0);
        if (!godEl.length) return;
        const powerClass = this.GOODS_ICONS[god];
        godEl.css({ zIndex: 10, cursor: 'pointer', borderRadius: '100%', outline: 'none',
                    boxShadow: '0px 0px 10px 5px rgba(255, 215, 0, 0.5)' });
        const powerEl = $(`.${powerClass}`).eq(0);
        if (!powerEl.length) return;
        godEl.click(() => {
            if (this.activeGodEl && this.activeGodEl.get(0) === godEl.get(0)) {
                clearInterval(this.loopFunct); this.loopFunct = null;
                this.setColor(this.activeGodEl.get(0), false); this.activeGodEl = null; return;
            }
            if (this.activeGodEl && this.activeGodEl.get(0) !== godEl.get(0)) {
                clearInterval(this.loopFunct); this.setColor(this.activeGodEl.get(0), false);
            }
            this.loopFunct = setInterval(() => this.clicker(powerEl), 1000);
            this.activeGodEl = godEl; this.setColor(godEl.get(0), true);
        });
    }

    setColor(elm, apply) {
        if (!elm) return;
        elm.style.filter = apply ? 'brightness(100%) sepia(100%) hue-rotate(90deg) saturate(1500%) contrast(0.8)' : '';
    }

    clicker(el) {
        const check = $('.js-power-icon.animated_power_icon.animated_power_icon_45x45.power_icon45x45.power').eq(0);
        if (!check.length) { clearInterval(this.loopFunct); this.loopFunct = null; this.activeGodEl = null; return; }
        el.click();
        const delta = 500;
        const rand = 500 + Math.floor(Math.random() * delta);
        clearInterval(this.loopFunct);
        this.loopFunct = setInterval(() => this.clicker(el), rand);
    }

    cast(id, type) {
        GameApi.ajaxPost('frontend_bridge', 'execute', {
            model_url: 'Commands',
            action_name: 'cast',
            arguments: { id, power_id: type },
        }, () => {});
    }
}


// Module: autoBootcamp.js
class AutoBootcamp extends ModernUtils {
    constructor() {
        super();
        this.active = this.loadSettings('ab_active', false);
        this.useDef = this.loadSettings('bootcamp_use_def', false);

        this.$title = this.getTitleElement('Auto Bootcamp').$title;
        this.$title.click(() => this.toggle());

        this.$btnOff = this.getButtonElement('Only off');
        this.$btnDef = this.getButtonElement('Off & Def');
        this.$btnOff.click(() => this.triggerUseDef());
        this.$btnDef.click(() => this.triggerUseDef());
        this._updateBtnStyle();

        const $div = $('<div>').css({ display: 'flex', justifyContent: 'center', padding: '10px' });
        $div.append(this.$btnOff, this.$btnDef);

        this.$settings = $('<div>');
        this.$settings.addClass('game_border').css({ margin: '20px' });
        this.$settings.css({
            'border-image-source': '',
            'border-image-slice': '',
            'border-image-width': '',
        });
        const $inner = $('<div>').css({ padding: '5px' });
        $inner.append(this.$title);
        $inner.append($div);
        this.$settings.append($inner);

        GameApi.onWindowOpen((e, handler) => {
            if (!handler?.attributes || handler.attributes.window_type !== 'attack_spot') return;
            const cid = handler.cid;
            const $window = $(`#window_${cid}`);
            $window.css('height', '660px');
            const iv = setInterval(() => {
                const $content = $window.find('.window_content');
                if ($content.length === 0) return;
                clearInterval(iv);
                $content.append(this.$settings.clone(true));
            }, 100);
        });
    }

    render() {
        const $box = $('<div>').css({ marginBottom: '20px' });
        $box.append(this.$title.clone(true).click(() => this.toggle()));
        const $div = $('<div>').css({ display: 'flex', justifyContent: 'center', padding: '10px' });
        $div.append(this.$btnOff.clone(true).click(() => this.triggerUseDef()));
        $div.append(this.$btnDef.clone(true).click(() => this.triggerUseDef()));
        $box.append($div);
        this._updateBtnStyle();
        return $box;
    }

    _updateBtnStyle() {
        if (this.useDef) {
            this.$btnOff.addClass('disabled');
            this.$btnDef.removeClass('disabled');
        } else {
            this.$btnDef.addClass('disabled');
            this.$btnOff.removeClass('disabled');
        }
        this.$title.toggleClass('active', this.active);
    }

    triggerUseDef() {
        this.useDef = !this.useDef;
        this.saveSettings('bootcamp_use_def', this.useDef);
        this._updateBtnStyle();
    }

    toggle() {
        this.active = !this.active;
        this.saveSettings('ab_active', this.active);
        this._updateBtnStyle();
    }

    async execute() {
        if (!this.active) return false;
        if (this._rewardBootcamp()) return true;
        if (this._attackBootcamp()) return true;
        return false;
    }

    _rewardBootcamp() {
        const model = GameApi.getModelByNameAndPlayerId('PlayerAttackSpot');
        if (!model || typeof model.getLevel === 'undefined') {
            this.active = false;
            this.saveSettings('ab_active', false);
            return true;
        }
        if (!model.hasReward()) return false;
        const reward = model.getReward();
        if (reward.power_id.includes('instant') && !reward.power_id.includes('favor')) {
            this._useReward();
            return true;
        }
        if (reward.stashable) this._stashReward();
        else this._useReward();
        return true;
    }

    _attackBootcamp() {
        const model = GameApi.getModelByNameAndPlayerId('PlayerAttackSpot');
        if (!model || model.getCooldownDuration() > 0) return false;

        const MovementsUnits = GameApi.getModels()?.MovementsUnits;
        if (MovementsUnits) {
            for (const mu of Object.values(MovementsUnits)) {
                if (mu.attributes.destination_is_attack_spot || mu.attributes.origin_is_attack_spot) return false;
            }
        }

        const town = GameApi.getCurrentTown();
        if (!town) return false;
        const units = { ...town.units() };
        delete units.militia;
        for (const unit in units) {
            if (GameApi.getUnitData(unit)?.is_naval) delete units[unit];
        }
        if (!this.useDef) {
            delete units.sword;
            delete units.archer;
        }
        if (Object.keys(units).length === 0) return false;

        const playerId = GameApi.playerId() || uw.Game?.player_id;
        GameApi.ajaxPost('frontend_bridge', 'execute', {
            model_url: `PlayerAttackSpot/${playerId}`,
            action_name: 'attack',
            arguments: units,
        }, () => {});
        return true;
    }

    _useReward() {
        const playerId = GameApi.playerId() || uw.Game?.player_id;
        GameApi.ajaxPost('frontend_bridge', 'execute', {
            model_url: `PlayerAttackSpot/${playerId}`,
            action_name: 'useReward',
            arguments: {},
        }, () => {});
    }

    _stashReward() {
        const playerId = GameApi.playerId() || uw.Game?.player_id;
        GameApi.ajaxPost('frontend_bridge', 'execute', {
            model_url: `PlayerAttackSpot/${playerId}`,
            action_name: 'stashReward',
            arguments: {},
        }, () => {}, () => this._useReward());
    }
}


// Module: autoBuild.js
class AutoBuild extends ModernUtils {
    SPRITES = {
        main:     '-450px 0px',
        storage:  '-250px -50px',
        farm:     '-150px 0px',
        academy:  '0px 0px',
        temple:   '-300px -50px',
        barracks: '-50px 0px',
        docks:    '-100px 0px',
        market:   '0px -50px',
        hide:     '-200px 0px',
        lumber:   '-400px 0px',
        stoner:   '-200px -50px',
        ironer:   '-250px 0px',
        wall:     '-50px -100px',
    };

    BUILDINGS = ['main', 'storage', 'farm', 'academy', 'temple', 'barracks', 'docks', 'market', 'hide', 'lumber', 'stoner', 'ironer', 'wall'];

    constructor() {
        super();
        this.townsBuildings = this.loadSettings('buildings', {});
        this.active = this.loadSettings('ab_active', false);
        GameApi.onWindowOpen((e, handler) => {
            if (handler?.context !== 'building_senate') return;
            this._updateSenate(handler);
        });
    }

    _updateSenate(handler) {
        handler.wnd.setWidth?.(850);
        const id = `gpwnd_${handler.wnd.getID?.()}`;
        const updateView = () => {
            const iv = setInterval(() => {
                const $w = $('#' + id);
                const $tasks = $w.find('#main_tasks');
                if (!$tasks.length) return;
                $tasks.hide();
                const $new = $('<div>').append('<p style="padding:10px">AutoBuild active. Set levels in ModernBot tab.</p>');
                $new.css({ position: $tasks.css('position'), left: parseInt($tasks.css('left')) - 20, top: $tasks.css('top') });
                $tasks.after($new);
                $w.find('#techtree').css({ position: 'relative', left: '40px' });
                $w.css({ overflowY: 'visible' });
                clearInterval(iv);
            }, 10);
            setTimeout(() => clearInterval(iv), 100);
        };
        const old = handler.wnd.setContent2;
        handler.wnd.setContent2 = (...a) => { updateView(); old?.(...a); };
    }

    render() {
        const { $container, $title } = this.getTitleElement('Auto Build');
        this.$container = $container;
        this.$title = $title;
        this.$title.click(() => this.toggle());
        if (this.active) this.$title.addClass('active');

        const town = GameApi.getCurrentTown();
        if (!town) return $container;
        const townId = String(town.id);
        const isActive = townId in this.townsBuildings;

        const $info = $('<div>').css({ padding: '6px' });
        $info.html(`<b>${town.getName()}</b> [${town.getPoints()} pts]`);
        $container.append($info);

        if (isActive) {
            const target = this.townsBuildings[townId] || {};
            const bld = GameApi.getBuildings(town.id);
            const $grid = $('<div>').css({ display: 'flex', flexWrap: 'wrap', gap: '4px', padding: '4px' });

            for (const name of this.BUILDINGS) {
                const cur = bld[name] || 0;
                const tgt = target[name] || 0;
                const sprite = this.SPRITES[name] || '0 0';

                const $box = $('<div>').addClass('auto_build_box').css({ margin: '2px' });
                const $bld = $('<div>').addClass('auto_build_building').css({ backgroundPosition: sprite });
                $box.append($bld);

                const $lvl = $('<div>').addClass('auto_build_lvl').text(`${cur}→${tgt}`);
                $box.append($lvl);

                const $up = $('<div>').addClass('auto_build_up_arrow').click(e => { e.stopPropagation(); this._editLevel(town.id, name, 1, e.shiftKey); });
                const $down = $('<div>').addClass('auto_build_down_arrow').click(e => { e.stopPropagation(); this._editLevel(town.id, name, -1, e.shiftKey); });
                $box.append($up, $down);

                $grid.append($box);
            }
            $container.append($grid);
        }
        return $container;
    }

    _editLevel(townId, name, d, shift) {
        const tid = String(townId);
        if (!(tid in this.townsBuildings)) return;
        const bld = GameApi.getBuildings(townId);
        if (!bld) return;
        const data = GameApi.getBuildingData(name);
        if (!data?.max_level) return;
        const cur = bld[name] || 0;
        const target = this.townsBuildings[tid];
        d = shift ? d * 10 : d;
        target[name] = Math.min(Math.max(cur + d, data.min_level || 0), data.max_level);
        this.townsBuildings[tid] = target;
        this.saveSettings('buildings', this.townsBuildings);
    }

    toggle() {
        const town = GameApi.getCurrentTown();
        if (!town) return;
        const tid = String(town.id);
        if (tid in this.townsBuildings) {
            delete this.townsBuildings[tid];
        } else {
            this.townsBuildings[tid] = {};
            const bld = GameApi.getBuildings(town.id);
            for (const n of this.BUILDINGS) this.townsBuildings[tid][n] = bld[n] || 0;
        }
        this.saveSettings('buildings', this.townsBuildings);
        this.active = Object.keys(this.townsBuildings).length > 0;
        this.$title.toggleClass('active', this.active);
    }

    async execute() {
        for (const townId of Object.keys(this.townsBuildings)) {
            const town = GameApi.getTown(townId);
            if (!town) { delete this.townsBuildings[townId]; this.saveSettings('buildings', this.townsBuildings); continue; }
            if (this._isFullQueue(town)) continue;
            if (this._isDone(town)) { delete this.townsBuildings[townId]; this.saveSettings('buildings', this.townsBuildings); continue; }
            await this._getNextBuild(townId);
            return true;
        }
        return false;
    }

    _isFullQueue(town) {
        const len = town.buildingOrders?.()?.length || 0;
        return len >= (GameApi.isAdvisorActive('curator') ? 7 : 2);
    }

    _isDone(town) {
        const tid = String(town.id);
        const bld = GameApi.getBuildings(town.id);
        const target = this.townsBuildings[tid] || {};
        for (const b of Object.keys(target)) { if (target[b] !== bld[b]) return false; }
        return true;
    }

    async _postBuild(type, townId) {
        const town = GameApi.getTown(townId);
        if (!town) return;
        const res = GameApi.getResources(townId);
        const bdd = GameApi.getBuildingBuildData(townId);
        if (!bdd?.[type] || !res) return;
        const { resources_for, population_for } = bdd[type];
        if ((town.getAvailablePopulation?.() || 0) < population_for) return;
        const m = 20;
        if (res.wood < (resources_for.wood || 0) + m || res.stone < (resources_for.stone || 0) + m || res.iron < (resources_for.iron || 0) + m) return;
        GameApi.ajaxPost('frontend_bridge', 'execute', { model_url: 'BuildingOrder', action_name: 'buildUp', arguments: { building_id: type }, town_id: townId }, () => {});
        await this.sleep(1234);
    }

    async _postTearDown(type, townId) {
        GameApi.ajaxPost('frontend_bridge', 'execute', { model_url: 'BuildingOrder', action_name: 'tearDown', arguments: { building_id: type }, town_id: townId }, () => {});
        await this.sleep(1234);
    }

    async _getNextBuild(townId) {
        const town = GameApi.getTown(townId);
        if (!town) return;
        const bld = { ...(GameApi.getBuildings(townId) || {}) };
        for (const o of (town.buildingOrders?.()?.models || [])) {
            if (o.attributes.tear_down) bld[o.attributes.building_type] = (bld[o.attributes.building_type] || 0) - 1;
            else bld[o.attributes.building_type] = (bld[o.attributes.building_type] || 0) + 1;
        }
        const target = this.townsBuildings[String(townId)] || {};

        const check = async (build, level) => {
            if (Array.isArray(build)) { build.sort(() => Math.random() - 0.5); for (const el of build) { if (await check(el, level)) return true; } return false; }
            if ((target[build] || 0) <= (bld[build] || 0)) return false;
            if ((bld[build] || 0) < level) { await this._postBuild(build, townId); return true; }
            return false;
        };
        const tearCheck = async build => {
            if (Array.isArray(build)) { build.sort(() => Math.random() - 0.5); for (const el of build) { if (await tearCheck(el)) return true; } return false; }
            if ((target[build] || 0) < (bld[build] || 0)) { await this._postTearDown(build, townId); return true; }
            return false;
        };

        if ((bld['docks'] || 0) < 1) {
            if (await check('lumber', 3)) return; if (await check('stoner', 3)) return; if (await check('farm', 4)) return;
            if (await check('ironer', 3)) return; if (await check('storage', 4)) return; if (await check('temple', 3)) return;
            if (await check('main', 5)) return; if (await check('barracks', 5)) return; if (await check('storage', 5)) return;
            if (await check('stoner', 6)) return; if (await check('lumber', 6)) return; if (await check('ironer', 6)) return;
            if (await check('main', 8)) return; if (await check('farm', 8)) return; if (await check('market', 6)) return;
            if (await check('storage', 8)) return; if (await check('academy', 7)) return; if (await check('temple', 5)) return;
            if (await check('farm', 12)) return; if (await check('main', 15)) return; if (await check('storage', 12)) return;
            if (await check('main', 25)) return; if (await check('hide', 10)) return;
        }
        if (await check('farm', 15)) return;
        if (await check(['storage', 'main'], 25)) return;
        if (await check('market', 4)) return;
        if (await check('hide', 10)) return;
        if (await check(['lumber', 'stoner', 'ironer'], 15)) return;
        if (await check(['academy', 'farm'], 36)) return;
        if (await check(['docks', 'barracks'], 10)) return;
        if (await check('wall', 25)) return;
        if (await check(['docks', 'barracks', 'market'], 20)) return;
        if (await check('farm', 45)) return;
        if (await check(['docks', 'barracks', 'market'], 30)) return;
        if (await check(['lumber', 'stoner', 'ironer'], 40)) return;
        if (await check('temple', 30)) return;
        if (await check('storage', 35)) return;
        const lista = ['lumber', 'stoner', 'ironer', 'docks', 'barracks', 'market', 'temple', 'academy', 'farm', 'hide', 'storage', 'wall'];
        if (await tearCheck(lista)) return;
        if (await tearCheck('main')) return;
    }
}


// Module: autoFarm.js
class AutoFarm extends ModernUtils {
    constructor() {
        super();

        this.active = this.loadSettings('farm_active', false);
        this.duration = this.loadSettings('farm_duration', 5);
    }

    render() {
        const { $container, $title } = this.getTitleElement('Auto Farm');
        this.$container = $container;
        this.$title = $title;

        this.$title.click(() => this.toggle());
        if (this.active) this.$title.addClass('active');

        this.$buttonBox = $('<div>').css({ "padding": "5px" })
        this.$container.append(this.$buttonBox);

        this.$button1 = this.getButtonElement("5 / 10 min")
        this.$button1.click(() => this.setDuration(1));
        this.$button2 = this.getButtonElement("20 / 40 min")
        this.$button2.click(() => this.setDuration(2));

        this.setDuration(this.duration);
        this.$buttonBox.append(this.$button1, this.$button2)

        return this.$container;
    }

    toggle() {
        this.active = !this.active;
        this.saveSettings('farm_active', this.active);
        this.$title.toggleClass('active');
    }

    setDuration(duration) {
        this.duration = duration;
        this.saveSettings('farm_duration', duration);

        this.$button1.removeClass('disabled');
        this.$button2.removeClass('disabled');

        if (duration === 1) this.$button1.addClass('disabled');
        if (duration === 2) this.$button2.addClass('disabled');
    }

    async execute() {
        if (!this.active) return false;

        const next_collection = this.getNextCollection();
        console.log('Next collection in', next_collection);
        if (next_collection > 0) return false;

        this.polis_list = this.generateList();
        await this.claim();

        return true;
    }

    // TODO: Ensure that this list has the right sorting
    generateList = () => {
        const islands_list = new Set();
        const polis_list = [];
        let minResource = 0;
        let min_percent = 0;

        const { models: towns } = uw.MM.getOnlyCollectionByName('Town');

        for (const town of towns) {
            const { on_small_island, island_id, id } = town.attributes;
            if (on_small_island || islands_list.has(island_id)) continue;

            // Check the min percent for each town
            const { wood, stone, iron, storage } = uw.ITowns.getTown(id).resources();
            minResource = Math.min(wood, stone, iron);
            min_percent = minResource / storage;

            islands_list.add(island_id);
            polis_list.push(town.id);
        }

        return polis_list;
    };


    getNextCollection = () => {
        const { models } = uw.MM.getCollections().FarmTownPlayerRelation[0];

        const lootCounts = {};
        for (const model of models) {
            const { lootable_at } = model.attributes;
            if (!lootable_at) continue;
            lootCounts[lootable_at] = (lootCounts[lootable_at] || 0) + 1;
        }

        let maxLootableTime = 0;
        let maxValue = 0;
        for (const lootableTime in lootCounts) {
            const value = lootCounts[lootableTime];
            if (value < maxValue) continue;
            maxLootableTime = lootableTime;
            maxValue = value;
        }

        const seconds = maxLootableTime - Math.floor(Date.now() / 1000);
        return seconds > 0 ? seconds * 1000 : 0;
    };


    async claim() {
        const isCaptainActive = uw.GameDataPremium.isAdvisorActivated('captain');

        // If the captain is active, claim all the resources at once and fake the opening
        if (isCaptainActive) {
            console.log('Claiming resources all at once');

            await this.fakeOpening();
            await this.sleep(Math.random() * 2000 + 1000);
            await this.fakeSelectAll();
            await this.sleep(Math.random() * 2000 + 1000);

            if (this.duration == 1) await this.claimMultiple(300, 600);
            if (this.duration == 2) await this.claimMultiple(1200, 2400);
            await this.fakeUpdate();

            setTimeout(() => uw.WMap.removeFarmTownLootCooldownIconAndRefreshLootTimers(), 2000);
            return;
        }

        console.log('Claiming resources one by one');

        // If the captain is not active, claim the resources one by one, but limit the number of claims
        // let max = 60;
        // const { models: player_relation_models } = uw.MM.getOnlyCollectionByName('FarmTownPlayerRelation');
        // const { models: farm_town_models } = uw.MM.getOnlyCollectionByName('FarmTown');
        // const now = Math.floor(Date.now() / 1000);
        // for (let town_id of polis_list) {
        //     let town = uw.ITowns.towns[town_id];
        //     let x = town.getIslandCoordinateX();
        //     let y = town.getIslandCoordinateY();
        //     for (let farm_town of farm_town_models) {
        //         if (farm_town.attributes.island_x != x) continue;
        //         if (farm_town.attributes.island_y != y) continue;
        //         for (let relation of player_relation_models) {
        //             if (farm_town.attributes.id != relation.attributes.farm_town_id) continue;
        //             if (relation.attributes.relation_status !== 1) continue;
        //             if (relation.attributes.lootable_at !== null && now < relation.attributes.lootable_at) continue;
        //             this.claimSingle(town_id, relation.attributes.farm_town_id, relation.id, Math.ceil(this.timing / 600_000));
        //             await this.sleep(500);
        //             if (!max) return;
        //             else max -= 1;
        //         }
        //     }
        // }

    }

    /* Claim resources from a single polis */
    claimSingle = (town_id, farm_town_id, relation_id, option = 1) => {
        const data = {
            model_url: `FarmTownPlayerRelation/${relation_id}`,
            action_name: 'claim',
            arguments: {
                farm_town_id: farm_town_id,
                type: 'resources',
                option: option,
            },
            town_id: town_id,
        };
        uw.gpAjax.ajaxPost('frontend_bridge', 'execute', data);
    };

    /* Claim resources from multiple polis */
    claimMultiple = (base = 300, boost = 600) =>
        new Promise((myResolve, myReject) => {
            const polis_list = this.generateList();
            let data = {
                towns: polis_list,
                time_option_base: base,
                time_option_booty: boost,
                claim_factor: 'normal',
            };
            uw.gpAjax.ajaxPost('farm_town_overviews', 'claim_loads_multiple', data, false, () => myResolve());
        });

    /* Pretend that the window it's opening */
    fakeOpening = () =>
        new Promise((myResolve, myReject) => {
            uw.gpAjax.ajaxGet('farm_town_overviews', 'index', {}, false, async () => {
                await this.sleep(10);
                await this.fakeUpdate();
                myResolve();
            });
        });

    /* Fake the user selecting the list */
    fakeSelectAll = () =>
        new Promise((myResolve, myReject) => {
            const data = {
                town_ids: this.polislist,
            };
            uw.gpAjax.ajaxGet('farm_town_overviews', 'get_farm_towns_from_multiple_towns', data, false, () => myResolve());
        });

    /* Fake the window update*/
    fakeUpdate = () =>
        new Promise((myResolve, myReject) => {
            const town = uw.ITowns.getCurrentTown();
            const { attributes: booty } = town.getResearches();
            const { attributes: trade_office } = town.getBuildings();
            const data = {
                island_x: town.getIslandCoordinateX(),
                island_y: town.getIslandCoordinateY(),
                current_town_id: town.id,
                booty_researched: booty ? 1 : 0,
                diplomacy_researched: '',
                trade_office: trade_office ? 1 : 0,
            };
            uw.gpAjax.ajaxGet('farm_town_overviews', 'get_farm_towns_for_town', data, false, () => myResolve());
        });

}   

// Module: autoGratis.js
class AutoGratis extends ModernUtils {
    constructor() {
        super();
        this.enabled = this.loadSettings('autogratis_enabled', false);
        this.onlyActiveTown = this.loadSettings('autogratis_only_active_town', false);
        this.$container = null;
        this.$title = null;
    }

    render() {
        if (!this.$container) {
            const title = this.getTitleElement('Auto Gratis');
            this.$container = title.$container;
            this.$title = title.$title;
            this.$title.click(() => this.toggle());
        }
        this.$title.css('filter', this.enabled ? 'brightness(100%) saturate(186%) hue-rotate(241deg)' : '');

        const $body = $('<div>').css({ padding: '5px', fontWeight: 600 });

        const $dummy = $('<div>').addClass('btn_time_reduction button_new').css({ display: 'inline-block', marginBottom: '8px' });
        $dummy.append($('<div>').addClass('left'));
        $dummy.append($('<div>').addClass('right'));
        $dummy.append($('<div>').addClass('caption js-caption').html('Gratis <div class="effect js-effect"></div>'));
        $body.append($dummy);

        $body.append($('<div>').css({ fontSize: '11px', fontWeight: 500 }).append(
            $('<label>').css({ cursor: 'pointer' }).append(
                $('<input>', { type: 'checkbox', checked: this.onlyActiveTown }).on('change', (e) => {
                    this.onlyActiveTown = e.target.checked;
                    this.saveSettings('autogratis_only_active_town', this.onlyActiveTown);
                })
            ).append(' Only fire on the actively-viewed town')
        ));

        this.$container.find('.game_border').nextAll().remove();
        this.$container.append($body);
        return this.$container;
    }

    toggle() {
        this.enabled = !this.enabled;
        this.saveSettings('autogratis_enabled', this.enabled);
        if (this.$title) {
            this.$title.css('filter', this.enabled ? 'brightness(100%) saturate(186%) hue-rotate(241deg)' : '');
        }
    }

    async execute() {
        if (!this.enabled) return false;
        if (GameApi.isCaptchaActive()) return false;

        const now = Math.floor(Date.now() / 1000);

        if (this.onlyActiveTown) {
            const town = GameApi.getCurrentTown();
            return this.tryTown(town, now);
        }

        const towns = Object.entries(uw.ITowns.towns || {});
        for (const [, town] of towns) {
            if (this.tryTown(town, now)) return true;
        }
        return false;
    }

    tryTown(town, now) {
        if (!town || typeof town.buildingOrders !== 'function') return false;
        const orders = town.buildingOrders();
        if (!orders?.models?.length) return false;
        const order = orders.models[0];
        const completedAt = order.attributes?.to_be_completed_at;
        if (!completedAt) return false;
        const remaining = completedAt - now;
        if (remaining > 0 && remaining < 300) {
            this.callGratis(town.id, order.id);
            return true;
        }
        return false;
    }

    callGratis(townId, orderId) {
        GameApi.ajaxPost('frontend_bridge', 'execute', {
            model_url: `BuildingOrder/${orderId}`,
            action_name: 'buyInstant',
            arguments: { order_id: orderId },
            town_id: townId
        }, () => {});
        console.log(`[ModernBot] gratis: ${uw.ITowns.towns[townId]?.getName() || townId} order ${orderId}`);
    }
}


// Module: autoHide.js
class AutoHide extends ModernUtils {
    constructor() {
        super();
        this.activeTown = this.loadSettings('autohide_active', 0);

        setInterval(() => this.main(), 5000);

        const addButton = () => {
            const box = $('.order_count');
            if (box.length) {
                const butt = $('<div/>', {
                    class: 'button_new',
                    id: 'autoCaveButton',
                    style: 'float: right; margin: 0px; left: 169px; position: absolute; top: 56px; width: 66px',
                });
                butt.append($('<div>').click(() => this.toggle()));
                butt.append($('<div>').addClass('left'));
                butt.append($('<div>').addClass('right'));
                butt.append($('<div>').addClass('caption js-caption').html('Auto <div class="effect js-effect"></div>'));
                box.prepend(butt);
                this.updateStyle(GameApi.getCurrentTown()?.id);
            } else {
                setTimeout(addButton, 100);
            }
        };

        GameApi.onWindowOpen((e, data) => {
            if (!data?.attributes) return;
            if (data.attributes.window_type !== 'hide') return;
            setTimeout(addButton, 100);
        });

        GameApi.onTownSwitch(() => {
            const town = GameApi.getCurrentTown();
            if (town) this.updateStyle(town.id);
            const cave = document.getElementsByClassName('js-window-main-container classic_window hide')[0];
            if (!cave) return;
            setTimeout(addButton, 1);
        });
    }

    render() {
        const title = this.getTitleElement('Auto Hide');
        title.$title.css('filter', this.activeTown ? 'brightness(100%) saturate(186%) hue-rotate(241deg)' : '');
        title.$title.click(() => this.toggle());
        this.$title = title.$title;

        const $body = $('<div>').css({ padding: '5px', fontWeight: 600 });
        $body.text('Check every 5s — stores iron > 15k in hide (lvl 10 required)');
        title.$container.append($body);
        return title.$container;
    }

    toggle(townId) {
        const town = townId ? GameApi.getTown(townId) : GameApi.getCurrentTown();
        if (!town) return;
        const hide = GameApi.getBuildings(town.id).hide || 0;
        if (this.activeTown === town.id) {
            this.activeTown = 0;
        } else {
            if (hide === 10) this.activeTown = town.id;
            else GameApi.notifyError('Hide must be at level 10');
        }
        this.saveSettings('autohide_active', this.activeTown);
        this.updateStyle(town.id);
    }

    updateStyle(townId) {
        const active = townId === this.activeTown;
        const filter = active ? 'brightness(100%) saturate(186%) hue-rotate(241deg)' : '';
        $('#auto_cave_title, #autoCaveButton').css('filter', filter);
    }

    main() {
        if (!this.activeTown) return;
        const res = GameApi.getResources(this.activeTown);
        if (!res) return;
        if ((res.iron || 0) > 15000) {
            GameApi.ajaxPost('frontend_bridge', 'execute', {
                model_url: 'BuildingHide',
                action_name: 'storeIron',
                arguments: { iron_to_store: res.iron },
                town_id: this.activeTown,
            }, () => {});
        }
    }
}


// Module: autoParty.js
class AutoParty extends ModernUtils {
    constructor() {
        super();
        this.activeTypes = this.loadSettings('ap_types', { festival: false, procession: false, theater: false });
        this.single = this.loadSettings('ap_single', true);
        this.active = this.loadSettings('ap_enable', false);
    }

    render() {
        const { $container, $title } = this.getTitleElement('Auto Party');
        this.$container = $container;
        this.$title = $title;

        this.$title.click(() => this.toggle());
        if (this.active) this.$title.addClass('active');

        const $types = $('<div>').css({ padding: '5px' });
        ['festival', 'procession', 'theater'].forEach(type => {
            const $b = this.getButtonElement(type.charAt(0).toUpperCase() + type.slice(1));
            $b.click(() => this.triggerType(type));
            if (!this.activeTypes[type]) $b.addClass('disabled');
            $types.append($b);
        });

        const $mode = $('<div>').css({ padding: '5px' });
        const $single = this.getButtonElement('Single');
        const $multi = this.getButtonElement('All');
        $single.click(() => this.triggerMode(0));
        $multi.click(() => this.triggerMode(1));
        if (!this.single) $single.addClass('disabled');
        else $multi.addClass('disabled');
        $mode.append($single, $multi);

        $container.append($types, $mode);
        return $container;
    }

    triggerType(type) {
        this.activeTypes[type] = !this.activeTypes[type];
        this.saveSettings('ap_types', this.activeTypes);
    }

    triggerMode(val) {
        this.single = !val;
        this.saveSettings('ap_single', this.single);
    }

    toggle() {
        this.active = !this.active;
        this.saveSettings('ap_enable', this.active);
        this.$title.toggleClass('active');
    }

    async execute() {
        if (!this.active) return false;
        let triggered = false;
        if (this.activeTypes['procession']) triggered = await this.checkTriumph() || triggered;
        if (this.activeTypes['festival']) triggered = await this.checkParty() || triggered;
        if (this.activeTypes['theater']) triggered = await this.checkTheater() || triggered;
        return triggered;
    }

    getCelebrationsList(type) {
        const models = uw.MM?.getModels()?.Celebration;
        if (!models) return [];
        return Object.values(models)
            .filter(c => c.attributes.celebration_type === type)
            .map(c => c.attributes.town_id);
    }

    async checkParty() {
        let max = 10;
        const party = this.getCelebrationsList('party');
        if (this.single) {
            const towns = Object.keys(uw.ITowns.towns || {});
            for (const townId of towns) {
                if (party.includes(parseInt(townId))) continue;
                const town = GameApi.getTown(townId);
                if (!town) continue;
                const bld = GameApi.getBuildings(townId);
                if (bld.academy < 30) continue;
                const res = GameApi.getResources(townId);
                if (!res || res.wood < 15000 || res.stone < 18000 || res.iron < 15000) continue;
                this.makeCelebration('party', townId);
                await this.sleep(750);
                max--;
                if (max <= 0) break;
            }
        } else {
            if (party.length > 1) return false;
            this.makeCelebration('party');
        }
        return max < 10;
    }

    async checkTriumph() {
        let max = 10;
        const killModel = GameApi.getModelByNameAndPlayerId('PlayerKillpoints');
        const kp = killModel?.attributes || { att: 0, def: 0, used: 0 };
        let available = kp.att + kp.def - kp.used;
        if (available < 300) return false;
        const triumph = this.getCelebrationsList('triumph');
        // single/multiple swapped (intentionnel v1)
        if (!this.single) {
            const towns = Object.keys(uw.ITowns.towns || {});
            for (const townId of towns) {
                if (triumph.includes(parseInt(townId))) continue;
                this.makeCelebration('triumph', townId);
                await this.sleep(500);
                available -= 300;
                if (available < 300) break;
                max--;
                if (max <= 0) break;
            }
        } else {
            if (triumph.length > 1) return false;
            this.makeCelebration('triumph');
        }
        return max < 10;
    }

    async checkTheater() {
        let max = 10;
        const theater = this.getCelebrationsList('theater');
        if (this.single) {
            const towns = Object.keys(uw.ITowns.towns || {});
            for (const townId of towns) {
                if (theater.includes(parseInt(townId))) continue;
                const bld = GameApi.getBuildings(townId);
                if (bld.theater !== 1) continue;
                const res = GameApi.getResources(townId);
                if (!res || res.wood < 10000 || res.stone < 12000 || res.iron < 10000) continue;
                this.makeCelebration('theater', townId);
                await this.sleep(500);
                max--;
                if (max <= 0) break;
            }
        } else {
            if (theater.length > 1) return false;
            this.makeCelebration('theater');
        }
        return max < 10;
    }

    makeCelebration(type, townId) {
        if (typeof townId === 'undefined') {
            GameApi.ajaxPost('town_overviews', 'start_all_celebrations', { celebration_type: type }, () => {});
        } else {
            GameApi.ajaxPost('building_place', 'start_celebration', { celebration_type: type, town_id: townId }, () => {});
        }
    }
}


// Module: autoRuralLevel.js
class AutoRuralLevel extends ModernUtils {
    constructor() {
        super();
        this.ruralLevel = this.loadSettings('enable_autorural_level', 1);
        this.active = this.loadSettings('enable_autorural_level_active', false);
    }

    render() {
        const { $container, $title } = this.getTitleElement('Auto Rural Level');
        this.$container = $container;
        this.$title = $title;

        this.$title.click(() => this.toggle());
        if (this.active) this.$title.addClass('active');

        const $body = $('<div>').css({ padding: '5px' });
        for (let n = 1; n <= 6; n++) {
            const $b = this.getButtonElement(`lvl ${n}`);
            $b.click(() => this.setRuralLevel(n));
            if (this.ruralLevel === n) $b.addClass('disabled');
            $body.append($b);
        }
        this.$container.append($body);
        return this.$container;
    }

    setRuralLevel(n) {
        this.ruralLevel = n;
        this.saveSettings('enable_autorural_level', n);
    }

    toggle() {
        this.active = !this.active;
        this.saveSettings('enable_autorural_level_active', this.active);
        this.$title.toggleClass('active');
    }

    async execute() {
        if (!this.active) return false;

        const farmTowns = GameApi.getCollection('FarmTown');
        const relations = GameApi.getCollection('FarmTownPlayerRelation');
        const killModel = GameApi.getModelByNameAndPlayerId('PlayerKillpoints');
        const kp = killModel?.attributes || { att: 0, def: 0, used: 0 };
        const available = kp.att + kp.def - kp.used;

        const locked = relations.filter(r => r.attributes.relation_status === 0);
        const unlocked = relations.length - locked.length;

        if (locked.length > 0) {
            const discounts = [2, 8, 10, 30, 50, 100];
            if (unlocked < discounts.length && available < discounts[unlocked]) return false;
            if (available < 100) return false;

            const towns = this.generateList();
            for (const townId of towns) {
                const town = GameApi.getTown(townId);
                if (!town) continue;
                const x = GameApi.getIslandX(townId);
                const y = GameApi.getIslandY(townId);
                for (const ft of farmTowns) {
                    if (ft.attributes.island_x !== x || ft.attributes.island_y !== y) continue;
                    for (const rel of locked) {
                        if (ft.attributes.id !== rel.attributes.farm_town_id) continue;
                        GameApi.ajaxPost('frontend_bridge', 'execute', {
                            model_url: `FarmTownPlayerRelation/${rel.id}`,
                            action_name: 'unlock',
                            arguments: { farm_town_id: ft.attributes.id },
                            town_id: townId,
                        }, () => {});
                        console.log(`[ModernBot] unlocked ${ft.attributes.name}`);
                        return true;
                    }
                }
            }
        } else {
            const towns = this.generateList();
            const levelCosts = [1, 5, 25, 50, 100];
            for (let level = 1; level < this.ruralLevel; level++) {
                if (available < levelCosts[level - 1]) return false;
                for (const townId of towns) {
                    const town = GameApi.getTown(townId);
                    if (!town) continue;
                    const x = GameApi.getIslandX(townId);
                    const y = GameApi.getIslandY(townId);
                    for (const ft of farmTowns) {
                        if (ft.attributes.island_x !== x || ft.attributes.island_y !== y) continue;
                        for (const rel of relations) {
                            if (ft.attributes.id !== rel.attributes.farm_town_id) continue;
                            if (rel.attributes.expansion_at) continue;
                            if (rel.attributes.expansion_stage > level) continue;
                            GameApi.ajaxPost('frontend_bridge', 'execute', {
                                model_url: `FarmTownPlayerRelation/${rel.id}`,
                                action_name: 'upgrade',
                                arguments: { farm_town_id: ft.attributes.id },
                                town_id: townId,
                            }, () => {});
                            console.log(`[ModernBot] upgraded ${ft.attributes.name}`);
                            return true;
                        }
                    }
                }
            }
            this.active = false;
            this.saveSettings('enable_autorural_level_active', false);
        }
        return false;
    }

    generateList() {
        const towns = GameApi.getTowns();
        const seen = new Set();
        const list = [];
        for (const t of towns) {
            const { on_small_island, island_id, id } = t.attributes;
            if (on_small_island || seen.has(island_id)) continue;
            seen.add(island_id);
            list.push(id);
        }
        return list;
    }
}


// Module: autoRuralTrade.js
class AutoRuralTrade extends ModernUtils {
    constructor() {
        super();
        this.ratio = this.loadSettings('rt_ratio', 5);
        this.active = false;
        this.loopId = null;
        this.tradeResource = null;
        this.totalTrade = 0;
        this.doneTrade = 0;
    }

    render() {
        const title = this.getTitleElement('Auto Trade Resources');
        const $title = title.$title;
        $title.click(() => this.stop());

        this.$progress = $('<div>').addClass('progress_bar_auto').css({ width: '0%', height: '4px', position: 'relative', zIndex: 10 });
        $title.prepend(this.$progress);

        const $body = $('<div>').addClass('split_content');

        const $bts = $('<div>').css({ padding: '5px' });
        ['Iron', 'Stone', 'Wood'].forEach(r => {
            const $b = this.getButtonElement(r);
            $b.click(() => this.start(r.toLowerCase()));
            $bts.append($b);
        });
        $body.append($bts);

        const $ratio = $('<div>').css({ padding: '5px' });
        [0.25, 0.5, 0.75, 1.0, 1.25].forEach((val, i) => {
            const $b = this.getButtonElement(String(val));
            $b.click(() => this.setRatio(i + 1));
            if (this.ratio === i + 1) $b.addClass('disabled');
            $ratio.append($b);
        });
        $body.append($ratio);

        title.$container.append($body);
        return title.$container;
    }

    setRatio(n) {
        this.ratio = n;
        this.saveSettings('rt_ratio', n);
    }

    start(resource) {
        if (this.active) { this.stop(); return; }
        this.active = true;
        this.tradeResource = resource;
        this.totalTrade = Object.keys(uw.ITowns.towns || {}).length;
        this.doneTrade = 0;
        this.loopId = setInterval(() => this.tradeLoop(), 1500);
    }

    stop() {
        this.active = false;
        clearInterval(this.loopId);
        this.loopId = null;
        if (this.$progress) this.$progress.css('width', '0%');
    }

    async tradeLoop() {
        if (GameApi.isCaptchaActive()) return;
        if (this.doneTrade >= this.totalTrade) { this.stop(); return; }
        const towns = Object.keys(uw.ITowns.towns || {});
        await this.tradeWithRural(towns[this.doneTrade]);
        if (this.$progress) this.$progress.css('width', `${(this.doneTrade / this.totalTrade) * 100}%`);
        this.doneTrade++;
    }

    async tradeWithRural(townId) {
        const town = GameApi.getTown(townId);
        if (!town) return;
        if (GameApi.availableTradeCapacity(townId) < 3000) return;

        const farmTowns = GameApi.getFarmTowns();
        const relations = GameApi.getFarmPlayerRelations();
        const res = town.resources();
        const x = GameApi.getIslandX(townId);
        const y = GameApi.getIslandY(townId);

        for (const ft of farmTowns) {
            const a = ft.attributes;
            if (a.island_x !== x || a.island_y !== y) continue;
            if (a.resource_offer !== this.tradeResource) continue;
            if ((res[a.resource_demand] || 0) < 3000) continue;

            for (const rel of relations) {
                const ra = rel.attributes;
                if (a.id !== ra.farm_town_id) continue;
                if (ra.relation_status !== 1) continue;
                if (ra.current_trade_ratio < this.ratio * 0.25) continue;
                if (GameApi.availableTradeCapacity(townId) < 3000) continue;

                const cap = town.getAvailableTradeCapacity() || 0;
                if (cap < 100) return;
                const amount = cap > 3000 ? 3000 : cap;
                GameApi.ajaxPost('frontend_bridge', 'execute', {
                    model_url: `FarmTownPlayerRelation/${ra.id}`,
                    action_name: 'trade',
                    arguments: { farm_town_id: ra.farm_town_id, amount },
                    town_id: townId,
                }, () => {});
                await this.sleep(750);
            }
        }
    }
}


